-- 334_perf_add_fk_indexes.sql
-- Adds covering indexes on foreign-key columns flagged by Supabase advisor
-- `unindexed_foreign_keys`. Without these, parent UPDATE/DELETE has to scan
-- the child table to enforce the FK constraint.
--
-- All CREATE INDEX statements use IF NOT EXISTS so this is idempotent.
-- Rollback: DROP INDEX IF EXISTS public.idx_<table>_fk_<col>; for each line.

CREATE INDEX IF NOT EXISTS idx_affiliate_events_fk_share_id ON public."affiliate_events" ("share_id");
